class SlidingTagTopK {
  constructor(windowMs){ this.W=windowMs; this.tagMap=new Map(); this.heap=[]; this.ver=0; }
  _expire(tag, now){ const b=this.tagMap.get(tag); while (b.queue.length && b.queue[0].ts <= now - this.W){ b.sum -= b.queue.shift().val; } }
  addEvent(tag, userId, value, ts){ let b=this.tagMap.get(tag); if(!b){ b={sum:0, queue:[], ver:0}; this.tagMap.set(tag,b);} this._expire(tag, ts); b.queue.push({ts, val: value}); b.sum += value; this.ver++; // push new entry
    this._heapPush({sum: b.sum, tag, ver:this.ver}); }
  topK(K){ // lazy
    const res=[]; const seen=new Set(); while (res.length<K && this.heap.length){ const top=this._heapPop(); if (top.ver===this.tagMap.get(top.tag).ver){ res.push(top.tag); seen.add(top.tag); } }
    return res;
  }
}
