## Code Example
```javascript
class QuickCategoryGrouper {
  constructor(W){ this.W=W; this.last=new Map(); this.catSums=new Map(); this.catHeaps=new Map(); this.catTotal=new Map(); }
  addEvent(e){ const key=`${e.user_id}:${e.category}`; const prev=this.last.get(key); if(prev && prev.ts> e.ts-W){ this._applyDelta(e.category, e.value - prev.value); } else { this._applyDelta(e.category, e.value); }
    this.last.set(key,{value:e.value, ts:e.ts}); this._pushToHeap(e.category,{value:e.value, user:e.user_id, ts:e.ts}); }
  _applyDelta(cat, delta){ this.catTotal.set(cat,(this.catTotal.get(cat)||0)+delta); }
  _pushToHeap(cat, item){ if(!this.catHeaps.has(cat)) this.catHeaps.set(cat, []); this.catHeaps.get(cat).push(item); }
  topKCategories(K, currentTime){ // lazy pop to ensure validity
    const res=[]; for(const [cat, total] of this.catTotal){ res.push({cat, total}); }
    res.sort((a,b)=> b.total - a.total); return res.slice(0,K).map(r=>r.cat); }
}
```

