## Code Example
```javascript
class WaveTopK {
  constructor(W) {
    this.W = W;
    this.userMap = new Map(); // user_id -> {queue: [], sum}
    this.heap = new MaxHeap(); // stores [sum, user_id]
  }
  addEvent(userId, score, ts) {
    let entry = this.userMap.get(userId);
    if (!entry) {
      entry = { queue: [], sum: 0 };
      this.userMap.set(userId, entry);
    }
    entry.queue.push([ts, score]);
    entry.sum += score;
    this.heap.push([entry.sum, userId]);
  }
  topK(currentTime, K) {
    const seen = new Map();
    const res = [];
    while (res.length < K && !this.heap.isEmpty()) {
      const [sum, uid] = this.heap.pop();
      const ent = this.userMap.get(uid);
      if (!ent) continue;
      // expire check
      this.expireUser(uid, currentTime);
      if (ent.sum !== sum) {
        this.heap.push([ent.sum, uid]);
        continue;
      }
      res.push(uid);
    }
    // Reinsert popped elements
    for (const uid of res) this.heap.push([this.userMap.get(uid).sum, uid]);
    return res;
  }
  expireUser(userId, currentTime) {
    const ent = this.userMap.get(userId);
    if (!ent) return;
    while (ent.queue.length && ent.queue[0][0] <= currentTime - this.W) {
      const [, val] = ent.queue.shift();
      ent.sum -= val;
    }
  }
}
```

