class PerKeyRollingStats {
  constructor(W) { this.W = W; this.map = new Map(); this.heap = new MaxHeap(); }
  add(key, value, ts) {
    let rec = this.map.get(key) || { dq: [], sum: 0 };
    rec.dq.push([ts, value]);
    rec.sum += value;
    while (rec.dq.length && rec.dq[0][0] < ts - this.W) {
      const [t, v] = rec.dq.shift();
      rec.sum -= v;
    }
    this.map.set(key, rec);
    const avg = rec.sum / rec.dq.length;
    this.heap.push({ key, avg, validAt: ts, len: rec.dq.length });
  }
  topK(currentTime, K) {
    const res = [];
    while (res.length < K) {
      const top = this.heap.pop();
      if (!top) break;
      const rec = this.map.get(top.key);
      const avg = rec && rec.dq.length ? rec.sum / rec.dq.length : -Infinity;
      if (top.avg !== avg) continue; // stale entry
      res.push(top.key);
    }
    // optional: reinsert from a temp to preserve heap state
    return res;
