## Go Implementation
```go
type IPCounter struct {
    counts map[string]int
    heap   *MinHeap
    mu     sync.RWMutex
}

func (ic *IPCounter) processChunk(chunk []byte) {
    scanner := bufio.NewScanner(bytes.NewReader(chunk))
    for scanner.Scan() {
        ip := extractIP(scanner.Text())
        ic.mu.Lock()
        ic.counts[ip]++
        ic.mu.Unlock()
    }
}

func (ic *IPCounter) getTop10() []IPCount {
    heap := container.NewMinHeap(10)
    for ip, count := range ic.counts {
        if heap.Len() < 10 {
            heap.Push(IPCount{ip, count})
        } else if count > heap.Peek().Count {
            heap.Pop()
            heap.Push(IPCount{ip, count})
        }
    }
    return heap.ToSlice()
}
```

