## Key Concepts

1. **Circular bucket array** enables O(1) bucketing and automatic expiration of old events
2. **Hashmap aggregation** provides O(1) lookup and update for per-user totals across categories
3. **Max-heap with lazy deletion** avoids the overhead of rebuilding the heap on every expiration; stale entries are filtered on-demand during `topK`
4. **Lazy expiration** ensures we never scan individual events during query time—only expired buckets trigger cleanup

## Code Example

```javascript
class WindowedTopK {
  constructor(W) {
    this.W = W;
    this.buckets = new Array(W).fill(null).map(() => ({ head: null, tail: null, ts: null }));
    this.totals = new Map();
    this.heap = [];
    this.head = 0;
  }

  insertEvent(ts, userId, category, value) {
    const idx = ts % this.W;
    const bucket = this.buckets[idx];
    const event = { userId, category, value, ts, next: null };
    if (!bucket.head) bucket.head = bucket.tail = event;
    else bucket.tail = bucket.tail.next = event;
    bucket.ts = ts;

    this.totals.set(userId, (this.totals.get(userId) || 0) + value);
    this.heap.push({ total: this.totals.get(userId), userId, ts });
  }

  advanceTime(now) {
    const cutoff = now - this.W;
    while (this.buckets[this.head].ts !== null && this.buckets[this.head].ts < cutoff) {
      let event = this.buckets[this.head].head;
      while (event) {
        this.totals.set(event.userId, (this.totals.get(event.userId) || 0) - event.value);
        event = event.next;
      }
      this.buckets[this.head] = { head: null, tail: null, ts: null };
      this.head = (this.head + 1) % this.W;
    }
  }

  topK(now, K) {
    this.advanceTime(now);
    const result = [];
    let i = 0;
    while (result.length < K && i < this.heap.length) {
      const entry = this.heap[i++];
      if (this.totals.get(entry.userId) === entry.total) {
        result.push(entry.userId);
      }
    }
    return result;
  }
}
```

