```javascript
class SlidingWindowTopK {
  constructor(W) {
    this.W = W
    this.window = [] // acts as deque (push is at end, shift from start)
    this.counts = new Map()
    this.heap = [] // min-heap of [freq, value]
  }
  _pushHeap(pair) { /* heap push for [freq, value] */ }
  add(x) {
    this.window.push(x)
    this.counts.set(x, (this.counts.get(x) || 0) + 1)
    // push updated freq
    this._pushHeap([this.counts.get(x), x])
    if (this.window.length > this.W) {
      const y = this.window.shift()
      const f = (this.counts.get(y) || 0) - 1
      if (f <= 0) this.counts.delete(y)
      else this.counts.set(y, f)
      this._pushHeap([f, y])
    }
  }
  topK(K) {
    const res = []
    const seen = new Set()
    const pulled = []
    while (res.length < Math.min(K, this.counts.size) && this.heap.length) {
      const [freq, val] = this._popHeap()
      if (!this.counts.has(val) || this.counts.get(val) !== freq) continue
      if (!seen.has(val)) {
        seen.add(val)
        res.push(val)
        pulled.push([freq, val])
      }
    }
    // restore elements for future calls
    for (const p of pulled) this._pushHeap(p)
    return res
  }
}
```

