class WindowedTopKMap {
  constructor(windowWidth) {
    this.W = windowWidth;
    this.map = new Map();
    this.heap = new MinHeap();
  }

  addEvent(key, value, ts) {
    if (!this.map.has(key)) {
      this.map.set(key, { sum: 0, queue: [] });
    }
    const entry = this.map.get(key);
    entry.queue.push({ ts, value });
    entry.sum += value;
    this.heap.push({ sum: entry.sum, key });
  }

  advanceTime(now) {
    // Lazy cleanup handled in topKKeys
  }

  topKKeys(K, now) {
    const results = [];
    while (results.length < K && !this.heap.isEmpty()) {
      const top = this.heap.pop();
      const entry = this.map.get(top.key);
      if (!entry) continue;
      this._expire(entry.queue, now);
      if (Math.abs(entry.sum - top.sum) > 0.0001) continue;
      results.push(top.key);
    }
    return results;
  }

  _expire(queue, now) {
    while (queue.length && queue[0].ts <= now - this.W) {
      entry.sum -= queue.shift().value;
