## Code Example
```javascript
class EventProcessor {
  constructor(W) {
    this.W = W;
    this.latestByUserAction = new Map(); // (user_id,action) -> timestamp
    this.userTotals = new Map(); // user_id -> total_score
    this.userEvents = new Map(); // user_id -> linked list of (timestamp, score)
    this.maxHeap = new MaxHeap(); // (total_score, user_id)
  }

  addEvent(event) {
    const key = `${event.user_id}:${event.action}`;
    const latest = this.latestByUserAction.get(key);

    if (!latest || event.ts - latest > this.W) {
      // Update dedup map
      this.latestByUserAction.set(key, event.ts);

      // Update user total
      const currentTotal = this.userTotals.get(event.user_id) || 0;
      const newTotal = currentTotal + event.score;
      this.userTotals.set(event.user_id, newTotal);

      // Add to user's event list
      if (!this.userEvents.has(event.user_id)) {
        this.userEvents.set(event.user_id, new LinkedList());
      }
      this.userEvents.get(event.user_id).push({ts: event.ts, score: event.score});

      // Update heap
      this.maxHeap.insert({score: newTotal, user: event.user_id});
    }
  }

  getTopK(k, now) {
    this.expire(now);
    return this.maxHeap.getTopK(k);
  }

  expire(now) {
    for (const [userId, events] of this.userEvents) {
      while (events.length > 0 && now - events.head.ts > this.W) {
        const expired = events.shift();
        const currentTotal = this.userTotals.get(userId);
        const newTotal = currentTotal - expired.score;
        this.userTotals.set(userId, newTotal);

        if (newTotal > 0) {
          this.maxHeap.insert({score: newTotal, user: userId});
        }
      }
    }
  }
}
```

