// Memoized DFS
function solveMemo(s, delCost){
  const n = s.length;
  const memoCost = Array.from({length:n},()=>Array(n).fill(-1));
  const memoWays = Array.from({length:n},()=>Array(n).fill(0));
  const MOD = 1_000_000_007;
  function dfs(l,r){
    if (l>=r) return {cost:0, ways:1};
    if (memoCost[l][r]!==-1) return {cost:memoCost[l][r], ways:memoWays[l][r]};
    if (s[l]===s[r]){
      const res = dfs(l+1,r-1);
      memoCost[l][r]=res.cost;
      memoWays[l][r]=res.ways;
      return res;
    } else {
      const A = dfs(l+1,r);
      const B = dfs(l,r-1);
      let cost;
      let ways = 0;
      if (A.cost + delCost[l] < B.cost + delCost[r]){
        cost = A.cost + delCost[l];
        ways = A.ways;
      } else if (B.cost + delCost[r] < A.cost + delCost[l]){
        cost = B.cost + delCost[r];
        ways = B.ways;
      } else {
        cost = A.cost + Math.min(delCost[l], delCost[r]);
        ways = (A.ways + B.ways) % MOD;
      }
      memoCost[l][r]=cost; memoWays[l][r]=ways;
      return {cost, ways};
    }
  }
  return dfs(0,n-1);
}
```

