```javascript
function maxPathSumWithTurns(grid, K) {
  const n = grid.length, m = grid[0].length;
  const INF = -Infinity;
  const dp = Array.from({ length: n }, () =>
    Array.from({ length: m }, () =>
      Array.from({ length: K + 1 }, () => [INF, INF])
    )
  );

  dp[0][0][0][0] = dp[0][0][0][1] = grid[0][0];

  for (let i = 0; i < n; i++) {
    for (let j = 0; j < m; j++) {
      if (grid[i][j] === -1) continue;
      for (let t = 0; t <= K; t++) {
        if (j + 1 < m && grid[i][j+1] !== -1) {
          const newTurn = t + (i > 0 ? 1 : 0);
          if (newTurn <= K) {
            dp[i][j+1][newTurn][0] = Math.max(
              dp[i][j+1][newTurn][0],
              dp[i][j][t][1] + grid[i][j+1]
            );
          }
          dp[i][j+1][t][0] = Math.max(dp[i][j+1][t][0], dp[i][j][t][0] + grid[i][j+1]);
        }
        if (i + 1 < n && grid[i+1][j] !== -1) {
          const newTurn = t + (j > 0 ? 1 : 0);
          if (newTurn <= K) {
            dp[i+1][j][newTurn][1] = Math.max(
              dp[i+1][j][newTurn][1],
              dp[i][j][t][0] + grid[i+1][j]
            );
          }
          dp[i+1][j][t][1] = Math.max(dp[i+1][j][t][1], dp[i][j][t][1] + grid[i+1][j]);
        }
      }
    }
  }

  const result = Math.max(...dp[n-1][m-1].flat());
  return result === INF ? -1 : result;
}
```

