function minCostTopDown(n, steps, memo=new Map()){
  if(n===0) return 0
  if(n<0) return Infinity
  if(memo.has(n)) return memo.get(n)
  let best = Infinity
  for(let s of steps){
    const c = s + minCostTopDown(n-s, steps, memo)
    if(c < best) best = c
  }
  memo.set(n, best)
  return best
}

function minCostBottomUp(n, steps){
  const INF = Number.POSITIVE_INFINITY
  const dp = Array(n+1).fill(INF)
  dp[0] = 0
  for(let i=1; i<=n; i++){
    for(let s of steps){
      if(i>=s && dp[i-s] !== INF){
        dp[i] = Math.min(dp[i], s + dp[i-s])
      }
    }
  }
  return dp[n] === INF ? -1 : dp[n]
}
