function bottomUpCount(a, B) {
  const n = a.length, MOD = 1000000007;
  const dp = new Array(n+1).fill(0);
  dp[0] = 1;
  let left = 0, window = 0, acc = 0;
  for (let i = 1; i <= n; i++) {
    window += a[i-1];
    while (window > B) {
      window -= a[left];
      acc = (acc - dp[left] + MOD) % MOD;
      left++;
    }
    acc = (acc + dp[i-1]) % MOD;
    dp[i] = acc;
  }
  return dp[n];
}
