// Tabulation and Memo versions
function countTargetSumTab(nums, S) {
  const total = nums.reduce((a,b)=>a+b,0);
  if (Math.abs(S) > total || (total+S)%2 !== 0) return 0;
  const target = (total+S)/2;
  const dp = Array(target+1).fill(0);
  dp[0] = 1;
  for (const n of nums) {
    for (let t = target; t >= n; t--) dp[t] += dp[t-n];
  }
  return dp[target];
}

function countTargetSumMemo(nums, S) {
  const total = nums.reduce((a,b)=>a+b,0);
  if (Math.abs(S) > total || (total+S)%2 !== 0) return 0;
  const target = (total+S)/2;
  const memo = new Map();
  function dfs(i, sum){
    if (sum > target) return 0;
    if (i === nums.length) return sum === target ? 1 : 0;
    const key = i+':'+sum;
    if (memo.has(key)) return memo.get(key);
    const res = dfs(i+1, sum+nums[i]) + dfs(i+1, sum);
    memo.set(key, res);
    return res;
  }
  return dfs(0,0);
}
```

