function countPaths(grid, L){
  const n = grid.length, m = grid[0].length, MOD = 1000000007;
  if(grid[0][0] || grid[n-1][m-1]) return 0;
  const memo = Array.from({length:n},()=>Array.from({length:m},()=>Array.from({length:2},()=>Array(L+1).fill(-1))));
  const endI=n-1, endJ=m-1;
  function dfs(i,j,dir,run){
