    const val = memo[i][j][dir][run];
    if(val!==-1) return val;
    let res = 0;
    // right
    if(j+1<m){
      if((dir===0 && run<L) || dir===1){
        res = (res + dfs(i, j+1, 0, dir===0 ? run+1 : 1)) % MOD;
      }
