## Edge Cases

- **Empty subset (N=0)**: If N=0 and S=0, return 1 (one valid subset - empty set). If S>0, return 0.
- **Target S=0**: Always return 1 (the empty subset counts as one valid subset).
- **All elements greater than S**: No valid subsets exist, return 0.

## Code Example

```javascript
function countSubsets(nums, target) {
  const mod = 1_000_000_007;
  const n = nums.length;

  // Top-down with memoization
  const memo = Array.from({ length: n + 1 }, () => Array(target + 1).fill(-1));
  function dfs(i, s) {
    if (s === 0) return 1;
    if (i === 0) return 0;
    if (memo[i][s] !== -1) return memo[i][s];
    memo[i][s] = dfs(i - 1, s) % mod;
    if (s >= nums[i - 1]) {
      memo[i][s] = (memo[i][s] + dfs(i - 1, s - nums[i - 1])) % mod;
    }
    return memo[i][s];
  }
  return dfs(n, target);
}

// Bottom-up with space optimization
function countSubsetsBU(nums, target) {
  const mod = 1_000_000_007;
  const dp = Array(target + 1).fill(0);
  dp[0] = 1;

  for (const num of nums) {
    for (let s = target; s >= num; s--) {
      dp[s] = (dp[s] + dp[s - num]) % mod;
    }
  }
  return dp[target];
}
```

Both solutions run in O(N×S) time with the bottom-up approach using O(S) space.

