```javascript
// Top-down memoized
function minCost(A, D){
  const N = A.length;
  const memo = Array.from({length:D+1}, ()=> Array(N).fill(null));
  function solve(d, i){
    if (d === 1){
      let mn = Infinity, mx = -Infinity;
      for (let k = 0; k <= i; k++){ mn = Math.min(mn, A[k]); mx = Math.max(mx, A[k]); }
      return mn * mx;
    }
    if (memo[d][i] != null) return memo[d][i];
    let mn = Infinity, mx = -Infinity; let best = Infinity;
    for (let j = i; j >= d-1; j--){
      mn = Math.min(mn, A[j]); mx = Math.max(mx, A[j]);
      best = Math.min(best, solve(d-1, j-1) + mn*mx);
    }
    memo[d][i] = best; return best;
  }
  return solve(D, N-1);
}

// Bottom-up
function minCostBottom(A, D){
  const N = A.length, INF = 1e18;
  const dp = Array.from({length:D+1}, ()=> Array(N).fill(INF));
  // base: d = 1
  for (let i = 0; i < N; i++){
    let mn = A[i], mx = A[i];
    for (let j = i; j >= 0; j--){
      mn = Math.min(mn, A[j]); mx = Math.max(mx, A[j]);
      if (j === 0) dp[1][i] = Math.min(dp[1][i], mn*mx);
    }
  }
  for (let d = 2; d <= D; d++){
    for (let i = d-1; i < N; i++){
      let mn = A[i], mx = A[i];
      for (let j = i; j >= d-1; j--){
        mn = Math.min(mn, A[j]); mx = Math.max(mx, A[j]);
        dp[d][i] = Math.min(dp[d][i], dp[d-1][j-1] + mn*mx);
      }
    }
  }
  return dp[D][N-1];
}
```

