  const adj = Array.from({length: n}, () => []);
  for (const [u, v, w] of edges) adj[u].push([v, w]);
  const memo = Array.from({length: n}, () => Array(W + 1).fill(-1));
  const dfs = (u, rem) => {
    if (u === n - 1) return 1;
    if (memo[u][rem] !== -1) return memo[u][rem];
    let res = 0;
    for (const [v, w] of adj[u]) if (w <= rem) res = (res + dfs(v, rem - w)) % 1_000_000_007;
