```javascript
// Bottom-up DP in topological order
function countPathsBottomUp(n, edges, W) {
  const adj = Array.from({length: n}, () => []);
  const indeg = Array(n).fill(0);
  for (const [u, v, w] of edges) {
    adj[u].push([v, w]);
    indeg[v]++;
  }
  // Kahn's algorithm for topo order
  const q = [];
  for (let i = 0; i < n; i++) if (indeg[i] === 0) q.push(i);
  const topo = [];
  while (q.length) {
    const u = q.shift(); topo.push(u);
    for (const [v] of adj[u]) if (--indeg[v] === 0) q.push(v);
  }
  const dp = Array.from({length: n}, () => Array(W + 1).fill(0));
  dp[0][0] = 1;
  for (const u of topo) {
    for (const [v, w] of adj[u]) {
      for (let t = 0; t <= W - w; t++) {
        if (dp[u][t] !== 0) dp[v][t + w] = (dp[v][t + w] + dp[u][t]) % 1_000_000_007;
      }
    }
  }
  let ans = 0;
  for (let t = 0; t <= W; t++) ans = (ans + dp[n - 1][t]) % 1_000_000_007;
  return ans;
}
```

