function minCost(s, dict) {
  const n = s.length;
  const memo = new Array(n+1).fill(null);
  const choice = new Array(n).fill(null);

  function costAt(i, w) {
    let cost = 0;
    for (let j = 0; j < w.length; j++) {
      if (s[i+j] !== '?' && s[i+j] !== w[j]) {
        cost++;
      }
    }
    return cost;
  }

  function dp(i) {
    if (i === n) return 0;
    if (memo[i] !== null) return memo[i];

    let best = Infinity;
    let bestWord = null;

    for (const w of dict) {
      if (i + w.length <= n) {
        const c = costAt(i, w) + dp(i + w.length);
        if (c < best) {
          best = c;
          bestWord = w;
        }
      }
    }

    memo[i] = best;
    choice[i] = bestWord;
    return best;
  }

  const minCost = dp(0);
  if (minCost === Infinity) return -1;

  // Reconstruct segmentation
  const words = [];
  let i = 0;
  while (i < n) {
    words.push(choice[i]);
    i += choice[i].length;
  }

  return { cost: minCost, words };
}
```

