## Code Example
```javascript
function shortestPaths(n, edges, blocked, s, t) {
  const g = Array.from({ length: n }, () => []);
  for (const [v, u] of edges) if (!blocked[v] && !blocked[u]) g[v].push(u);
  const dist = Array(n).fill(Infinity);
  const ways = Array(n).fill(0);
  if (blocked[s] || blocked[t]) return { dist: -1, ways: 0 };
  dist[s] = 0; ways[s] = 1;
  const q = [s];
  while (q.length) {
    const v = q.shift();
    for (const u of g[v]) {
      if (dist[u] === Infinity) {
        dist[u] = dist[v] + 1; ways[u] = ways[v]; q.push(u);
      } else if (dist[u] === dist[v] + 1) {
        ways[u] = (ways[u] + ways[v]) % 1000000007;
      }
    }
  }
  return { dist: dist[t] === Infinity ? -1 : dist[t], ways: ways[t] };
}
```

## Follow-up Questions
