function countCriticalPaths(N, edges, dur) {
  const MOD = 1000000007;
  const incoming = Array.from({length: N}, () => []);
  const indeg = Array(N).fill(0);

  for (const [u, v, w] of edges) {
    incoming[v].push([u, w]);
    indeg[v]++;
  }

  const EFT = dur.slice();
  const count = Array(N).fill(0);
  const q = [];

  for (let i = 0; i < N; i++) {
    if (indeg[i] === 0) {
      count[i] = 1;
      q.push(i);
    }
  }

  while (q.length) {
    const u = q.shift();
    for (const [v, w] of incoming[u]) {
      const newEFT = EFT[u] + w + dur[v];
      if (newEFT > EFT[v]) {
        EFT[v] = newEFT;
        count[v] = count[u];
      } else if (newEFT === EFT[v]) {
        count[v] = (count[v] + count[u]) % MOD;
      }
      indeg[u]--;
      if (indeg[u] === 0) q.push(u);
    }
  }

  let maxEFT = 0, totalCritical = 0;
  for (let i = 0; i < N; i++) {
    if (EFT[i] > maxEFT) {
      maxEFT = EFT[i];
      totalCritical = count[i];
    } else if (EFT[i] === maxEFT) {
      totalCritical = (totalCritical + count[i]) % MOD;
    }
  }
  return { EFT, maxEFT, criticalPaths: totalCritical };
}
```

