function shortestWithBoosts(adj, s, t, K){
  const n = adj.length; const INF = 1e15;
  const dist = Array.from({length:n}, ()=>Array(K+1).fill(INF));
  const parent = Array.from({length:n}, ()=>Array(K+1).fill(null));
  dist[s][0] = 0;
