  pq.push({d:0,u:s,k:0});
  while(!pq.empty()){
    const {d,u,k} = pq.pop();
    if(d !== dist[u][k]) continue;
    for(const {to,w} of adj[u]){
      if(dist[to][k] > d + w){
        dist[to][k] = d+w; parent[to][k] = {u,k};
        pq.push({d: dist[to][k], u:to, k});
      }
      if(k < K){
        const ww = Math.floor(w/2);
        if(dist[to][k+1] > d + ww){
          dist[to][k+1] = d+ww; parent[to][k+1] = {u,k};
          pq.push({d: dist[to][k+1], u:to, k:k+1});
        }
      }
    }
  }
  let best = 0; for(let kk=1; kk<=K; kk++) if(dist[t][kk] < dist[t][best]) best = kk;
