## Key Concepts
- **State-Space Expansion:** Augment each vertex with a binary flag indicating coupon usage
- **Layer 0 (coupon unused):** Can transition to layer 0 (full cost) or layer 1 (half cost)
- **Layer 1 (coupon used):** Can only transition to layer 1 (full cost only)
- **Path Reconstruction:** Track predecessor states to identify which edge receives the discount

## Code Example
```javascript
function shortestWithCoupon(graph, s, t) {
  const n = graph.length;
  const dist = Array.from({ length: n }, () => [Infinity, Infinity]);
  const prev = Array.from({ length: n }, () => [null, null]);
  const pq = new PriorityQueue((a, b) => a.dist < b.dist);

  dist[s][0] = 0;
  pq.push({ u: s, used: 0, dist: 0 });

  while (!pq.isEmpty()) {
    const { u, used, dist: d } = pq.pop();
    if (d > dist[u][used]) continue;
    if (u === t) break;

    for (const { v, w } of graph[u]) {
      // Transition without using coupon
      if (d + w < dist[v][used]) {
        dist[v][used] = d + w;
        prev[v][used] = { u, used };
        pq.push({ u: v, used, dist: dist[v][used] });
      }
      // Transition using coupon (only if not yet used)
      if (used === 0) {
        const newDist = d + w / 2;
        if (newDist < dist[v][1]) {
          dist[v][1] = newDist;
          prev[v][1] = { u, used, discounted: { from: u, to: v, weight: w } };
          pq.push({ u: v, used: 1, dist: newDist });
        }
      }
    }
  }

  const best = dist[t][0] < dist[t][1] ? 0 : 1;
  return { distance: dist[t][best], finalState: best };
}
```

