function shortestConstrainedPath(G, S, T, M) {
  const topo = topoSort(G);
  const idx = (v) => topo.indexOf(v);

  const canReach = (from, to) => {
    if (idx(from) >= idx(to)) return false;
    const reachable = new Set([from]);
    for (let i = idx(from); i < idx(to); i++) {
      for (const edge of G.adj[topo[i]]) {
        if (idx(edge.to) < idx(to)) reachable.add(edge.to);
      }
    }
    return reachable.has(to);
  };

  const points = [S, ...M.map(e => e[0]), ...M.map(e => e[1]), T];
  for (let i = 0; i < points.length - 1; i++) {
    if (!canReach(points[i], points[i + 1])) return null;
  }

  const segmentCost = (src, dst) => {
    const dist = {}; dist[src] = 0;
    for (let i = idx(src); i < idx(dst); i++) {
      const u = topo[i];
      for (const edge of G.adj[u]) {
        if (idx(edge.to) < idx(dst)) {
          if (dist[u] + edge.w < (dist[edge.to] ?? Infinity)) {
            dist[edge.to] = dist[u] + edge.w;
          }
        }
      }
    }
    return dist[dst];
  };

  let total = 0;
  const fullPath = [S];
  for (const [u, v, w] of M) {
    total += w;
    const seg = segmentCost(fullPath[fullPath.length - 1], u);
    if (seg === undefined) return null;
    total += seg;
  }
  const finalSeg = segmentCost(M[M.length - 1][1], T);
  if (finalSeg === undefined) return null;
  return total + finalSeg;
}
```

