function shortestStats(n, edges, s, t) {
  const adj = Array.from({ length: n }, () => []);
  for (const [u, v, w] of edges) {
    adj[u].push([v, w]);
  }

  const dist = new Array(n).fill(Infinity);
  const pq = [[0, s]];
  dist[s] = 0;

  while (pq.length) {
    const [d, u] = pq.pop();
    if (d > dist[u]) continue;
    for (const [v, w] of adj[u]) {
      if (dist[u] + w < dist[v]) {
        dist[v] = dist[u] + w;
        pq.push([dist[v], v]);
      }
    }
  }

  const dag = Array.from({ length: n }, () => []);
  for (let u = 0; u < n; u++) {
    for (const [v, w] of adj[u]) {
      if (dist[u] + w === dist[v]) {
        dag[u].push(v);
      }
    }
  }

  const ways = new Array(n).fill(0);
  ways[s] = 1;
  const order = Array.from({ length: n }, (_, i) => i)
    .sort((a, b) => dist[a] - dist[b]);

  for (const u of order) {
    for (const v of dag[u]) {
      ways[v] = (ways[v] + ways[u]) % 1000000007;
    }
  }

  const path = [];
  let curr = t;
  while (curr !== null) {
    path.unshift(curr);
    const preds = dag
      .map((list, u) => list.includes(curr) ? u : -1)
      .filter(u => u >= 0 && dist[curr] === dist[u] + 
        adj[u].find(([v]) => v === curr)?.[1]);
    preds.sort((a, b) => a - b);
    curr = preds.length > 0 ? preds[0] : null;
    if (curr === s) {
      path.unshift(s);
      break;
    }
  }

  return { distance: dist[t], ways: ways[t], path };
}
```

