function shortestPathWithHops(graph, S, T, H) {
  // graph: {u: [{to,w}, ...], ...}
  const dist = new Map();
  const prev = new Map();
  // min-heap assumed available: push({time, node, hops})
  const heap = new MinHeap((a,b)=>a.time-b.time);
  dist.set(`${S}|0`, 0);
  heap.push({time:0, node:S, hops:0});
  while (!heap.isEmpty()) {
    const {time,u,k} = heap.pop();
    if (time !== dist.get(`${u}|${k}`)) continue;
    for (const {to:v, w} of (graph[u] || [])) {
      const nk = k + 1;
      if (nk > H) continue;
      const nd = time + w;
      const key = `${v}|${nk}`;
      if (nd < (dist.get(key) ?? Infinity)) {
        dist.set(key, nd);
        prev.set(key, `${u}|${k}`);
        heap.push({time: nd, node: v, hops: nk});
      }
    }
  }
  let bestTime = Infinity; let bestKey = null;
  for (let k = 0; k <= H; k++) {
    const key = `${T}|${k}`;
    const d = dist.get(key);
    if (d != null && d < bestTime) { bestTime = d; bestKey = key; }
  }
  const path = [];
  if (bestKey) {
    let cur = bestKey;
    while (cur) {
      const [node] = cur.split('|');
      path.push(node);
      cur = prev.get(cur);
    }
    path.reverse();
  }
  return { time: bestTime, path };
}
```

