function makespan(n, durations, edges) {
  // Build adjacency list and compute indegrees
  const adj = Array.from({length: n}, () => []);
  const indeg = Array(n).fill(0);

  for (const [u, v] of edges) {
    adj[u].push(v);
    indeg[v]++;
  }

  // Initialize earliest finish times
  const earliestFinish = durations.slice();
  const queue = [];

  // Start with source nodes (indegree = 0)
  for (let i = 0; i < n; i++) {
    if (indeg[i] === 0) queue.push(i);
  }

  // Process nodes in topological order
  let head = 0;
  while (head < queue.length) {
    const u = queue[head++];

    for (const v of adj[u]) {
      // Update earliest finish for successor
      earliestFinish[v] = Math.max(
        earliestFinish[v],
        earliestFinish[u] + durations[v]
      );

      indeg[v]--;
      if (indeg[v] === 0) queue.push(v);
    }
  }

  // Return makespan (maximum earliest finish time)
  return Math.max(...earliestFinish);
}
```

## Algorithm Insight
The topological approach ensures each node is processed only after all its predecessors are complete, allowing accurate computation of earliest start times and efficient makespan calculation.

