function shortestPathDAG(n, edges, start, target) {
  const g = Array.from({length: n}, () => []);
  for (const [u, v, w] of edges) g[u].push([v, w]);
  const visited = Array(n).fill(false);
  const topo = [];
  function dfs(u){
    visited[u] = true;
    for (const [v] of g[u]) if (!visited[v]) dfs(v);
    topo.push(u);
  }
  for (let i = 0; i < n; i++) if (!visited[i]) dfs(i);
  topo.reverse();
  const INF = Number.POSITIVE_INFINITY;
  const dist = Array(n).fill(INF);
  const parent = Array(n).fill(-1);
  dist[start] = 0;
  for (const u of topo) {
    if (dist[u] === INF) continue;
    for (const [v, w] of g[u]) {
      if (dist[u] + w < dist[v]) {
        dist[v] = dist[u] + w;
        parent[v] = u;
      }
    }
  }
  if (dist[target] === INF) return {time: -1, path: []};
  const path = [];
  for (let x = target; x != -1; x = parent[x]) path.push(x);
  path.reverse();
  return {time: dist[target], path};
}
```

