      const cand = [hops + 1, latency + (skip ? 0 : w)];
      const current = best.get(v);
      if (!current || lexicographicallySmaller(cand, current)) {
        best.set(v, cand);
        pred.set(v, u);
      }
    }
  }

  return reconstructPath(pred, s, t);
