function detectCycles(graph) {
  const visited = new Set();
  const recStack = new Set();

  function dfs(u) {
    if (recStack.has(u)) return true; // Cycle detected
    if (visited.has(u)) return false;

    visited.add(u);
    recStack.add(u);

    for (const {to: v} of graph.edgesFrom(u)) {
      if (dfs(v)) return true;
    }

    recStack.delete(u);
    return false;
  }

  return Array.from(graph.nodes()).some(dfs);
}
