function shortestWithDiscounts(n, edges, s, t, K) {
  const adj = Array.from({length: n}, ()=>[]);
  for(const [u,v,w] of edges){ adj[u].push([v,w]); }
  const INF = Number.POSITIVE_INFINITY;
  const dist = Array.from({length: n}, ()=> Array(K+1).fill(INF));
  const prev = Array.from({length: n}, ()=> Array(K+1).fill(null));

  const pq = new MinHeap();
  dist[s][0] = 0;
  pq.insert([s,0,0]); // [node, used, distance]

  while(!pq.isEmpty()){
    const [u,used,d] = pq.extractMin();
    if(d > dist[u][used]) continue;
    if(u === t) break;

    for(const [v,w] of adj[u]){
      // Without discount
      if(d + w < dist[v][used]){
        dist[v][used] = d + w;
        prev[v][used] = [u,used];
        pq.insert([v,used,d+w]);
      }
      // With discount if available
      if(used < K && d < dist[v][used+1]){
        dist[v][used+1] = d;
        prev[v][used+1] = [u,used];
        pq.insert([v,used+1,d]);
      }
    }
  }

  // Find optimal state at target
  let minDist = INF, minUsed = -1;
  for(let k=0;k<=K;k++){
    if(dist[t][k] < minDist){
      minDist = dist[t][k];
      minUsed = k;
    }
  }

  // Path reconstruction
  const path = [];
  let curr = [t,minUsed];
  while(curr && prev[curr[0]][curr[1]]){
    path.unshift(curr[0]);
    curr = prev[curr[0]][curr[1]];
  }
  if(curr[0] === s) path.unshift(s);

  return {distance: minDist, path};
}
```

