function introsort(arr) {
  const n = arr.length;
  const maxDepth = Math.floor(2 * Math.log2(n || 1));

  function sort(left, right, depth) {
    if (left >= right) return;

    if (depth === 0) {
      heapSort(arr, left, right);
      return;
    }

    const [lt, gt] = threeWayPartition(arr, left, right);

    // Sort smaller partition first (tail recursion optimization)
    if (lt - left < right - gt) {
      sort(left, lt - 1, depth - 1);
      sort(gt + 1, right, depth - 1);
    } else {
      sort(gt + 1, right, depth - 1);
      sort(left, lt - 1, depth - 1);
    }
  }

  sort(0, n - 1, maxDepth);
  return arr;
}
```

