// Skeleton: threeWayQuicksort(a, lo, hi) with lt/gt pointers
function threeWayQuicksort(a, lo = 0, hi = a.length - 1) {
  if (lo >= hi) return;

  const pivot = a[lo];
  let lt = lo, i = lo + 1, gt = hi;

  while (i <= gt) {
    if (a[i] < pivot) swap(a, lt++, i++);
    else if (a[i] > pivot) swap(a, i, gt--);
    else i++;
  }

  // Tail recurse on smaller subarray for O(log n) space
  if (gt - lo < hi - lt) {
    threeWayQuicksort(a, lo, lt - 1);
    lo = gt + 1;
  } else {
    threeWayQuicksort(a, gt + 1, hi);
    hi = lt - 1;
  }

  if (lo < hi) threeWayQuicksort(a, lo, hi);
}
```

