function sortBatch(arr) {
  const n = arr.length;
  const buf = new Array(n);
  function insertionSort(a, left, right) {
    for (let i = left + 1; i <= right; i++) {
      const key = a[i];
      let j = i - 1;
      while (j >= left && a[j] > key) {
