// Introsort skeleton in JS
function introsort(arr) {
  const n = arr.length;
  if (n <= 1) return;
  const maxDepth = Math.floor(2 * Math.log2(n));
  function swap(i, j) { const t = arr[i]; arr[i] = arr[j]; arr[j] = t; }
  function medianOfThree(lo, mid, hi) {
    if (arr[lo] > arr[mid]) swap(lo, mid);
    if (arr[lo] > arr[hi]) swap(lo, hi);
    if (arr[mid] > arr[hi]) swap(mid, hi);
    return mid;
  }
  function partition(lo, hi) {
    const mid = Math.floor((lo + hi) / 2);
    const m = medianOfThree(lo, mid, hi);
    swap(m, hi);
    const pivot = arr[hi];
    let i = lo;
    for (let j = lo; j < hi; j++) {
      if (arr[j] <= pivot) { swap(i, j); i++; }
    }
    swap(i, hi);
    return i;
  }
  function heapSort(lo, hi) {
    const n = hi - lo + 1;
    function heapify(i, size) {
      while (true) {
        const l = 2 * i + 1;
        const r = l + 1;
        let largest = i;
        if (l < size && arr[lo + l] > arr[lo + largest]) largest = l;
        if (r < size && arr[lo + r] > arr[lo + largest]) largest = r;
        if (largest !== i) { swap(lo + i, lo + largest); i = largest; } else break;
      }
    }
    for (let i = Math.floor(n / 2) - 1; i >= 0; i--) heapify(i, n);
    for (let end = n - 1; end > 0; end--) {
      swap(lo, lo + end);
      heapify(0, end);
    }
  }
  function insertionSort(lo, hi) {
    for (let i = lo + 1; i <= hi; i++) {
      const key = arr[i];
      let j = i - 1;
      while (j >= lo && arr[j] > key) { arr[j + 1] = arr[j]; j--; }
      arr[j + 1] = key;
    }
  }
  function quickSort(lo, hi, depth) {
    const size = hi - lo + 1;
    if (size <= 16) { insertionSort(lo, hi); return; }
    if (depth <= 0) { heapSort(lo, hi); return; }
    const p = partition(lo, hi);
    quickSort(lo, p - 1, depth - 1);
    quickSort(p + 1, hi, depth - 1);
  }
  quickSort(0, n - 1, maxDepth);
}
```

