```javascript
class MinHeap {
  constructor() { 
    this.heap = []; 
  }

  size() { 
    return this.heap.length; 
  }

  push(item) {
    this.heap.push(item);
    this._heapifyUp(this.heap.length - 1);
  }

  pop() {
    if (this.heap.length === 0) return null;
    const min = this.heap[0];
    const last = this.heap.pop();
    if (this.heap.length > 0) {
      this.heap[0] = last;
      this._heapifyDown(0);
    }
    return min;
  }

  _heapifyUp(index) { /* implementation */ }
  _heapifyDown(index) { /* implementation */ }
}

function kWayMerge(arr) {
  // Edge case: empty input
  if (arr.length === 0) return [];

  // Detect runs
  const runs = [];
  let start = 0;

  for (let i = 1; i <= arr.length; i++) {
    if (i === arr.length || arr[i-1] > arr[i]) {
      runs.push({start, end: i-1, index: start});
      start = i;
    }
  }

  // Edge case: r=1 (already sorted)
  if (runs.length === 1) return arr.slice();

  // Initialize heap with first elements
  const heap = new MinHeap();
  const result = [];

  runs.forEach((run, i) => {
    heap.push({value: arr[run.index], runId: i});
  });

  // Merge process
  while (heap.size() > 0) {
    const {value, runId} = heap.pop();
    result.push(value);

    const run = runs[runId];
    if (run.index < run.end) {
      run.index++;
      heap.push({value: arr[run.index], runId});
    }
  }

  return result;
}
```

