function mergeTwo(l1, l2) {
  const dummy = { val: 0, next: null };
  let tail = dummy;
  while (l1 && l2) {
    if (l1.val <= l2.val) {
      tail.next = l1;
      l1 = l1.next;
    } else {
      tail.next = l2;
      l2 = l2.next;
    }
    tail = tail.next;
  }
  tail.next = l1 || l2;
  return dummy.next;
}

function sortList(head) {
  if (!head || !head.next) return head;
  // length
  let len = 0, p = head;
  while (p) { len++; p = p.next; }
  const dummy = { next: head };
  for (let w = 1; w < len; w <<= 1) {
    let prev = dummy;
    let curr = dummy.next;
    while (curr) {
      // split left
      let left = curr;
      let i = 1;
      while (i < w && curr && curr.next) { curr = curr.next; i++; }
      const right = curr.next;
      curr.next = null;
      // split right
      curr = right;
      i = 1;
      while (i < w && curr && curr.next) { curr = curr.next; i++; }
      const next = curr ? curr.next : null;
      if (curr) curr.next = null;
      const merged = mergeTwo(left, right);
      prev.next = merged;
      while (prev.next) prev = prev.next;
      curr = next;
    }
  }
  return dummy.next;
}
```

