## Code Example

```javascript
function sortByWeightAndValue(arr) {
  const popcount = (n) => {
    n = n >>> 0;
    n = n - ((n >>> 1) & 0x55555555);
    n = (n & 0x33333333) + ((n >>> 2) & 0x33333333);
    n = (n + (n >>> 4)) & 0x0f0f0f0f;
    return (n * 0x01010101) >>> 24;
  };
  const items = arr.map(v => ({ val: v, w: popcount(v) }));
  const mergeSort = (a) => {
    if (a.length <= 1) return a.slice();
    const m = Math.floor(a.length / 2);
    const L = mergeSort(a.slice(0, m));
    const R = mergeSort(a.slice(m));
    const res = [];
    let i = 0, j = 0;
    while (i < L.length && j < R.length) {
      if (L[i].w !== R[j].w) res.push(L[i].w < R[j].w ? L[i++] : R[j++]);
      else res.push(L[i].val <= R[j].val ? L[i++] : R[j++]);
    }
    while (i < L.length) res.push(L[i++]);
    while (j < R.length) res.push(R[j++]);
    return res;
  };
  const sorted = mergeSort(items);
  return sorted.map(o => o.val);
}
```

Why This Is Asked\n\nThis question probes understanding of practical sorting trade-offs beyond textbook asymptotics, including cache locality, in-place constraints, and robust pivot strategies. It invites discussion of 3-way partitioning to handle duplicates, median-of-three to curb worst-case behavior, and a small insertion sort for tiny partitions.\n\n## Key Concepts\n- 3-way partitioning in quicksort\n- median-of-three pivot selection\n- insertion sort threshold tuning\n- in-place algorithms and cache efficiency\n- iterative vs recursive implementations\n\n## Code Example\n```javascript
function sortInPlace(arr){
  const TH = 16;
  const swap=(a,i,j)=>{const t=a[i]; a[i]=a[j]; a[j]=t;};
  const medianOfThree=(a,i,j,k)=>{let x=[a[i],i],[a[j],j],[a[k],k].sort((p,q)=>p[0]-q[0]); return a[x[1]];};
  // iterative 3-way quicksort skeleton
  const stack=[[0,arr.length-1]];
  while(stack.length){
    const [lo,hi]=stack.pop();
    if(hi-lo+1<=TH){ // insertion sort for small partitions
      for(let i=lo+1;i<=hi;i++){
        let t=arr[i], j=i-1;
        while(j>=lo && arr[j]>t){ arr[j+1]=arr[j]; j-- }
        arr[j+1]=t;
      }
      continue;
    }
    // median-of-three pivot
    const mid=(lo+hi)>>1;
    const pivot= medianOfThree(arr, lo, mid, hi);
    // 3-way partition
    let lt=lo, i=lo, gt=hi;
    while(i<=gt){
      if(arr[i]<pivot) swap(arr, lt++, i++);
      else if(arr[i]>pivot) swap(arr, i, gt--);
      else i++;
    }
    stack.push([lo, lt-1]);
    stack.push([gt+1, hi]);
  }
}
