  while(!heap.isEmpty()){
    const {val,pos,runIdx}=heap.pop();
    out[k++]=val;
    const [l,r]=runs[runIdx];
    const next=pos+1;
    if(next<r) heap.push({val:a[next], pos:next, runIdx});
