  const left=a.slice(l,m); let i=0, j=m, t=l;
  while(i<left.length && j<r) a[t++]= left[i++]<a[j]? left[i-1]: a[j++];
  while(i<left.length) a[t++]=left[i++];
  while(j<r) a[t++]=a[j++];
