class MinHeap{
  constructor(cmp){ this.a=[]; this.cmp=cmp||((x,y)=> x<y); }
  push(x){ this.a.push(x); this.bubbleUp(this.a.length-1); }
  pop(){ if(this.a.length===0) return null; const top=this.a[0]; const end=this.a.pop(); if(this.a.length){ this.a[0]=end; this.sinkDown(0); } return top; }
  isEmpty(){ return this.a.length===0; }
  bubbleUp(n){ const a=this.a[n]; while(n>0){ const p=(n-1)>>1; if(this.cmp(a, this.a[p])){ this.a[n]=this.a[p]; n=p; } else break; } this.a[n]=a; }
  sinkDown(n){ const length=this.a.length; const element=this.a[n]; while(true){ let child2=(n+1)*2, child1=child2-1; let swap=null; if(child1<length){ if(this.cmp(this.a[child1], element)) swap=child1; } if(child2<length){ if(this.cmp(this.a[child2], swap===null?element:this.a[child1])) swap=child2; } if(swap===null) break; this.a[n]=this.a[swap]; n=swap; } this.a[n]=element; }
}
