function inPlaceMerge(arr, left, mid, right) {
  let i = left, j = mid + 1;
  while (i <= mid && j <= right) {
    if (arr[i] <= arr[j]) { i++; continue; }
    const tmp = arr[j];
    for (let k = j; k > i; k--) arr[k] = arr[k - 1];
    arr[i] = tmp;
    i++; mid++; j++;
  }
