  constructor() {
    this.root = new TrieNode();
    this.wordSet = new Set();
  }

  insert(word) {
    if (this.wordSet.has(word)) return;
    this.wordSet.add(word);
    let node = this.root;
    for (const char of word) {
      if (!node.next.has(char)) {
        node.next.set(char, new TrieNode());
      }
      node = node.next.get(char);
      node.passCount++;
    }
    node.isWord = true;
  }

  countPrefix(prefix) {
    let node = this.root;
    for (const char of prefix) {
      if (!node.next.has(char)) return 0;
      node = node.next.get(char);
    }
    return node.passCount;
