    let node = this.root;
    for (const char of prefix) {
      if (!node.next.has(char)) return [];
      node = node.next.get(char);
    }
    const result = [];
    this.dfs(node, prefix, result, limit);
    return result;
  }

  dfs(node, current, result, limit) {
    if (result.length >= limit) return;
    if (node.isWord) {
      result.push(current);
    }
    const sortedKeys = Array.from(node.next.keys()).sort();
    for (const char of sortedKeys) {
      this.dfs(node.next.get(char), current + char, result, limit);
