## Code Example
```javascript
class TrieNode {
  constructor() {
    this.children = new Map();
    this.pass = 0;
    this.end = 0;
  }
}

class Trie {
  constructor() {
    this.root = new TrieNode();
  }

  insert(word) {
    let node = this.root;
    node.pass++;
    for (const ch of word) {
      if (!node.children.has(ch)) {
        node.children.set(ch, new TrieNode());
      }
      node = node.children.get(ch);
      node.pass++;
    }
    node.end++;
  }

  exists(word) {
    const node = this._findNode(word);
    return node !== null && node.end > 0;
  }

  countPrefix(prefix) {
    const node = this._findNode(prefix);
    return node ? node.pass : 0;
  }

  erase(word) {
    if (!this.exists(word)) return false;

    let node = this.root;
    node.pass--;

    for (const ch of word) {
      const child = node.children.get(ch);
      child.pass--;
      if (child.pass === 0) {
        node.children.delete(ch);
        node = null;
        break;
      }
      node = child;
    }

    if (node) node.end--;
    return true;
  }

  _findNode(word) {
    let node = this.root;
    for (const ch of word) {
      if (!node.children.has(ch)) return null;
      node = node.children.get(ch);
    }
    return node;
  }
}

// Usage
const trie = new Trie();
trie.insert('apple');
trie.insert('apple');
trie.insert('app');
trie.exists('apple');        // true
trie.countPrefix('app');      // 3
trie.erase('apple');
trie.exists('apple');        // true (still one left)
trie.countPrefix('app');     // 2
trie.erase('apple');
trie.exists('apple');        // false
trie.countPrefix('app');      // 1
trie.erase('nonexistent');   // false (safe)
```

