class SegTree {
  constructor(arr) {
    this.n = arr.length;
    this.size = 1;
    while (this.size < this.n) this.size <<= 1;
    this.tree = new Array(this.size * 2).fill(-Infinity);
    for (let i = 0; i < this.n; i++) this.tree[this.size + i] = arr[i];
    for (let i = this.size - 1; i > 0; i--) this.tree[i] = Math.max(this.tree[i<<1], this.tree[i<<1|1]);
  }
  update(idx, val) {
    let pos = this.size + idx;
    this.tree[pos] = val;
    for (pos >>= 1; pos > 0; pos >>= 1) {
      this.tree[pos] = Math.max(this.tree[pos<<1], this.tree[pos<<1|1]);
    }
  }
  query(l, r) {
    let res = -Infinity;
    l += this.size; r += this.size;
    while (l <= r) {
      if (l & 1) res = Math.max(res, this.tree[l++]);
      if (!(r & 1)) res = Math.max(res, this.tree[r--]);
      l >>= 1; r >>= 1;
    }
    return res;
  }
}
