## Key Concepts
- Trie with terminal weights for efficient prefix matching
- Dynamic insert/delete operations on Trie structure
- Weighted word-break DP with O(n × L) complexity where L = maxWordLen
- Both iterative bottom-up DP and memoized top-down DFS variants

## Code Example
```javascript
class TrieNode {
  constructor() {
    this.children = new Map();
    this.endWeight = 0;
    this.isEnd = false;
  }
}

class WeightedTrie {
  constructor() {
    this.root = new TrieNode();
    this.maxWordLen = 0;
  }

  insert(word, weight) {
    let node = this.root;
    for (const char of word) {
      if (!node.children.has(char)) {
        node.children.set(char, new TrieNode());
      }
      node = node.children.get(char);
    }
    node.isEnd = true;
    node.endWeight = weight;
    this.maxWordLen = Math.max(this.maxWordLen, word.length);
  }

  delete(word) {
    let node = this.root;
    for (const char of word) {
      if (!node.children.has(char)) return;
      node = node.children.get(char);
    }
    node.isEnd = false;
    node.endWeight = 0;
  }

  maxPartition(s) {
    const n = s.length;
    const dp = new Array(n + 1).fill(-1);
    dp[n] = 0;

    for (let i = n - 1; i >= 0; i--) {
      let node = this.root;
      for (let j = i; j < Math.min(n, i + this.maxWordLen); j++) {
        const char = s[j];
        if (!node.children.has(char)) break;
        node = node.children.get(char);
        if (node.isEnd && dp[j + 1] !== -1) {
          dp[i] = Math.max(dp[i], node.endWeight + dp[j + 1]);
        }
      }
    }
    return dp[0];
  }

  maxPartitionDFS(s, memo = {}) {
    if (s.length === 0) return 0;
    if (s in memo) return memo[s];

    let maxWeight = -1;
    let node = this.root;

    for (let i = 0; i < Math.min(s.length, this.maxWordLen); i++) {
      const char = s[i];
      if (!node.children.has(char)) break;
      node = node.children.get(char);

      if (node.isEnd) {
        const remaining = this.maxPartitionDFS(s.slice(i + 1), memo);
        if (remaining !== -1) {
          maxWeight = Math.max(maxWeight, node.endWeight + remaining);
        }
      }
    }
    memo[s] = maxWeight;
    return maxWeight;
  }
}
```

