class Node {
  constructor(key) {
    this.key = key;
    this.cnt = 1;
    this.height = 1;
    this.left = null;
    this.right = null;
    this.sum = key;
  }
}

function getHeight(node) { return node ? node.height : 0; }
function getSum(node) { return node ? node.sum : 0; }
function update(node) {
  node.height = 1 + Math.max(getHeight(node.left), getHeight(node.right));
  node.sum = getSum(node.left) + node.key * node.cnt + getSum(node.right);
}

function rightRotate(y) {
  const x = y.left;
  y.left = x.right;
  x.right = y;
  update(y);
  update(x);
  return x;
}

function rangeSum(node, a, b) {
  if (!node) return 0;
  if (node.key < a) return rangeSum(node.right, a, b);
  if (node.key > b) return rangeSum(node.left, a, b);
  return getSum(node.left) + node.key * node.cnt + rangeSum(node.right, a, b);
}
