class TrieNode {
  constructor() {
    this.next = new Array(26).fill(null);
    this.pass = 0;
    this.isWord = false;
  }
}

class Trie {
  constructor() {
    this.root = new TrieNode();
  }

  insert(word) {
    let node = this.root;
    for (const char of word) {
      const idx = char.charCodeAt(0) - 97;
      if (!node.next[idx]) node.next[idx] = new TrieNode();
      node.pass++;
      node = node.next[idx];
    }
    node.pass++;
    node.isWord = true;
