  countWithPrefix(prefix) {
    let node = this.root;
    for (const char of prefix) {
      const idx = char.charCodeAt(0) - 97;
      if (!node.next[idx]) return 0;
      node = node.next[idx];
    }
    return node.pass;
  }
}

