class Autocomplete {
  constructor() {
    this.root = new TrieNode();
  }

  addWord(word, freq) {
    let node = this.root;
    for (const char of word) {
      if (!node.children.has(char)) {
        node.children.set(char, new TrieNode());
      }
      node = node.children.get(char);
    }
    node.freq = freq;
  }

  getSuggestions(prefix, limit) {
    if (limit <= 0) return [];

    let node = this.root;
    for (const char of prefix) {
      if (!node.children.has(char)) return [];
      node = node.children.get(char);
    }

    const results = [];
    const dfs = (currentNode, path) => {
      if (currentNode.freq > 0) {
        results.push({ word: path, freq: currentNode.freq });
      }
      for (const [char, childNode] of currentNode.children) {
        dfs(childNode, path + char);
      }
    };

    dfs(node, prefix);

    results.sort((a, b) => {
      if (b.freq !== a.freq) return b.freq - a.freq;
      return a.word.localeCompare(b.word);
    });

    return results.slice(0, limit).map(r => r.word);
  }
}
```

