## Code Example

```javascript
class TrieNode {
  constructor() {
    this.children = new Map();
    this.subtreeCount = 0;
    this.isWord = false;
  }
}

class Trie {
  constructor() {
    this.root = new TrieNode();
  }

  insert(word) {
    if (!word || typeof word !== 'string') {
      return;
    }

    let node = this.root;
    node.subtreeCount++;

    for (const char of word) {
      if (!node.children.has(char)) {
        node.children.set(char, new TrieNode());
      }
      node = node.children.get(char);
      node.subtreeCount++;
    }

    node.isWord = true;
  }

  getPrefixCount(prefix) {
    if (!prefix || typeof prefix !== 'string') {
      return 0;
    }

    let node = this.root;

    for (const char of prefix) {
      if (!node.children.has(char)) {
        return 0;
      }
      node = node.children.get(char);
    }

    return node.subtreeCount;
  }
}

// Example usage:
const trie = new Trie();
trie.insert('cat');
trie.insert('cater');
trie.insert('category');
trie.insert('dog');

console.log(trie.getPrefixCount('cat'));  // 3 (cat, cater, category)
console.log(trie.getPrefixCount('ca'));   // 3
console.log(trie.getPrefixCount('c'));    // 3
console.log(trie.getPrefixCount('dog'));  // 1
console.log(trie.getPrefixCount('z'));    // 0 (non-existent prefix)
console.log(trie.getPrefixCount(''));     // 0 (empty string)
console.log(trie.getPrefixCount(null));   // 0 (null input)
```

## Complexity Analysis

- **Time Complexity**: O(m) for insert, O(k) for getPrefixCount where m is word length and k is prefix length
- **Space Complexity**: O(ALPHABET_SIZE × m × n) where m is average word length and n is number of words, but optimized with Map-based children

